code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, Breadcrumb, icon } from 'decantr/components';

code.example:
function DetailHeader({ data }) {
  const { div, h1, p, nav, a } = tags;

  return div({ class: css('_flex _col _gap4 _pb4 _bbsolid _bcborder') },
    Breadcrumb({},
      Breadcrumb.Item({}, a({ href: '/' }, 'Home')),
      Breadcrumb.Item({}, a({ href: '/items' }, 'Items')),
      Breadcrumb.Item({ current: true }, data?.title || 'Detail')
    ),
    div({ class: css('_flex _row _jcsb _aic') },
      div({ class: css('_flex _col _gap1') },
        div({ class: css('_flex _row _gap3 _aic') },
          h1({ class: css('_heading2') }, data?.title || 'Item Title'),
          Badge({ variant: 'default' }, data?.status || 'Active')
        ),
        p({ class: css('_bodysm _fgmuted') }, data?.description || 'Item description goes here')
      ),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline', size: 'sm' }, icon('share'), 'Share'),
        Button({ variant: 'outline', size: 'sm' }, icon('edit'), 'Edit'),
        Button({ variant: 'destructive', size: 'sm' }, icon('trash'), 'Delete')
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Badge, Button, icon } from 'decantr/components';

code.example:
function DetailHeaderProfile({ data }) {
  const { div, h1, p, span } = tags;

  const stats = [
    { label: 'Followers', value: '1,234' },
    { label: 'Following', value: '567' },
    { label: 'Posts', value: '89' },
  ];

  return div({ class: css('_flex _row _gap6 _items[start]') },
    Avatar({ size: 'xl', src: data?.avatar, fallback: data?.initials || 'U' }),
    div({ class: css('_flex _col _gap2 _flex1') },
      div({ class: css('_flex _row _gap3 _aic') },
        h1({ class: css('_heading2') }, data?.name || 'User Name'),
        Badge({ variant: 'secondary' }, data?.role || 'Member')
      ),
      p({ class: css('_bodysm _fgmuted') }, data?.title || 'Software Engineer'),
      p({ class: css('_body _fgmuted') }, data?.bio || 'No bio provided.'),
      div({ class: css('_flex _gap6 _mt2') },
        ...stats.map(s =>
          div({ class: css('_flex _col _aic') },
            span({ class: css('_textlg _fontbold') }, s.value),
            span({ class: css('_textxs _fgmuted') }, s.label)
          )
        )
      ),
      div({ class: css('_flex _gap2 _mt3') },
        Button({ variant: 'primary', size: 'sm' }, icon('user-plus'), 'Follow'),
        Button({ variant: 'outline', size: 'sm' }, icon('mail'), 'Message')
      )
    )
  );
}

